SELECT COUNT(id)
FROM dylan_liuli
WHERE del_flag = '0'

    AND DATE(create_time) >= #{beginDate}
    AND DATE(create_time) <= #{endDate}

SELECT COUNT(id)
FROM dylan_liuli
WHERE del_flag = '0'

    AND DATE(create_time) >= #{beginDate}
    AND DATE(create_time) <= #{endDate}

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS name, COUNT(id) AS value FROM dylan_liuli WHERE del_flag = '0'
AND DATE(create_time) >= #{beginDate} AND DATE(create_time) <= #{endDate}
GROUP BY DATE_FORMAT(create_time, '%Y-%m-%d') ORDER BY name

SELECT dc.name AS name, COUNT(dl.id) AS value FROM dylan_liuli dl LEFT JOIN dylan_catagory dc ON dl.liuli_cat = dc.id WHERE dl.del_flag = '0' AND dc.name IS NOT NULL
AND DATE(dl.create_time) >= #{beginDate} AND DATE(dl.create_time) <= #{endDate}
GROUP BY dc.name

SELECT dt.name AS name, COUNT(dlt.tag_id) AS value FROM dylan_liuli_tag dlt LEFT JOIN dylan_tag dt ON dlt.tag_id = dt.id LEFT JOIN dylan_liuli dl ON dlt.liuli_id = dl.id WHERE dl.del_flag = '0'
AND DATE(dl.create_time) >= #{beginDate} AND DATE(dl.create_time) <= #{endDate}
GROUP BY dt.name ORDER BY value DESC LIMIT #{limit}

SELECT publish_author AS name, COUNT(id) AS value FROM dylan_liuli WHERE del_flag = '0' AND publish_author IS NOT NULL AND publish_author != ''
AND DATE(create_time) >= #{beginDate} AND DATE(create_time) <= #{endDate}
GROUP BY publish_author ORDER BY value DESC LIMIT #{limit}
